n  // Extension method: \"native_extend\" | \"last_frame_chain\"\n  extensionMethod String @default(\"native_extend\")\n\n  // Target & progress\n  targetDurationSec  Int\n  currentDurationSec Float @default(0)\n  totalClips         Int   @default(1)\n  completedClips     Int   @default(0)\n\n  // Final output\n  finalVideoUrl   String?\n  finalStorageKey String?\n  generationId    String?     @unique\n  generation      Generation? @relation(fields: [generationId], references: [id], onDelete: SetNull)\n\n  // Reference for character consistency\n  characterCardIds  String[] @default([])\n  referenceImageUrl String?\n  apiKeyId          String?\n\n  errorMessage String?  @db.Text\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  clips VideoPipelineClip[]\n\n  @@index([userId, createdAt(sort: Desc)])\n  @@index([status, createdAt(sort: Desc)])\n}\n\nmodel VideoPipelineClip {\n  id         String             @id @default(uuid())\n  pipelineId String\n  pipeline   VideoPipeline      @relation(fields: [pipelineId], references: [id], onDelete: Cascade)\n  clipIndex  Int\n  status     PipelineClipStatus @default(PENDING)\n\n  // Job tracking\n  generationJobId   String?\n  externalRequestId String? @db.Text\n\n  // Clip result\n  videoUrl     String?\n  storageKey   String?\n  lastFrameUrl String?\n  durationSec  Float?\n\n  // Extension input\n  inputVideoUrl String? // For native extend: previous clip's video URL\n  inputFrameUrl String? // For last-frame chain: previous clip's last frame\n\n  errorMessage String?   @db.Text\n  startedAt    DateTime?\n  completedAt  DateTime?\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  @@unique([pipelineId, clipIndex])\n  @@index([pipelineId, clipIndex])\n  @@index([status, createdAt(sort: Desc)])\n}\n\n// ─── LoRA Training ────────────────────────────────────────────────\n\nmodel LoraTrainingJob {\n  id                 String             @id @default(uuid())\n  userId             String\n  user               User               @relation(fields: [userId], references: [id], onDelete: Cascade)\n  name               String\n  triggerWord        String\n  loraType           String             @default(\"subject\") // \"subject\" | \"style\"\n  baseModel          String             @default(\"flux-dev\")\n  trainingImageKeys  String[] // R2 storage keys\n  status             LoraTrainingStatus @default(QUEUED)\n  externalTrainingId String? // Replicate training ID\n  progress           Float              @default(0) // 0-1\n  errorMessage       String?            @db.Text\n  loraUrl            String? // Trained LoRA URL\n  loraStorageKey     String? // R2 backup key\n  createdAt          DateTime           @default(now())\n  startedAt          DateTime?\n  completedAt        DateTime?\n\n  characterCardId String?\n  characterCard   CharacterCard? @relation(fields: [characterCardId], references: [id], onDelete: SetNull)\n\n  loraAsset LoraAsset?\n\n  @@index([userId, status, createdAt(sort: Desc)])\n}\n\n// ─── LoRA Asset (reusable, style-code addressable) ────────────────\n\nmodel LoraAsset {\n  id String @id @default(uuid())\n\n  // userId is nullable so curated/platform LoRAs can exist without an owner\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Human-facing label + URL-safe short code for cross-tool sharing\n  name      String\n  styleCode String @unique // e.g. \"pv-ghibli-soft-7k2x\"\n\n  source          String @default(\"trained\") // \"curated\" | \"trained\" | \"imported\"\n  type            String @default(\"subject\") // \"subject\" | \"style\"\n  baseModelFamily String @default(\"flux\") // \"flux\" | \"sdxl\" | ...\n  provider        String @default(\"fal\") // adapter routing hint\n\n  triggerWord      String\n  loraUrl          String // direct download URL passed to provider\n  storageKey       String? // R2 key (null for curated/external)\n  previewImageUrls Json? // string[] — auto-generated preview gallery\n  coverImageUrl    String? // single hero image for cards\n\n  defaultScale Float @default(1.0)\n\n  trainingJobId String?          @unique\n  trainingJob   LoraTrainingJob? @relation(fields: [trainingJobId], references: [id], onDelete: SetNull)\n\n  isPublic   Boolean   @default(false)\n  usageCount Int       @default(0)\n  lastUsedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId, createdAt(sort: Desc)])\n  @@index([source, isPublic, createdAt(sort: Desc)])\n}\n\n// ─── Video Script (VS1-VS11) ──────────────────────────────────────\n\nmodel VideoScript {\n  id              String             @id @default(cuid())\n  userId          String\n  user            User               @relation(fields: [userId], references: [id], onDelete: Cascade)\n  topic           String             @db.Text\n  targetDuration  Int // 30 | 60 | 120 (seconds)\n  totalScenes     Int // derived from targetDuration\n  status          VideoScriptStatus  @default(DRAFT)\n  consistencyMode String // 'character_card' | 'first_frame_ref'\n  characterCardId String? // required when consistencyMode = 'character_card'\n  styleCardId     String? // optional global style\n  videoModelId    String // 'seedance-2-fast' | 'kling-pro'\n  finalVideoUrl   String?\n  scenes          VideoScriptScene[]\n  createdAt       DateTime           @default(now())\n  updatedAt       DateTime           @updatedAt\n\n  @@index([userId, createdAt(sort: Desc)])\n  @@index([userId, status, createdAt(sort: Desc)])\n}\n\nmodel VideoScriptScene {\n  id                String                 @id @default(cuid())\n  scriptId          String\n  script            VideoScript            @relation(fields: [scriptId], references: [id], onDelete: Cascade)\n  orderIndex        Int\n  duration          Int\n  cameraShot        String\n  action            String                 @db.Text\n  dialogue          String?                @db.Text\n  transition        String // 'cut' | 'fade' | 'dissolve' (Phase 1 only 'cut')\n  frameGenerationId String? // VS10: plain string, no FK\n  clipGenerationId  String? // VS10: plain string, no FK\n  status            VideoScriptSceneStatus @default(PENDING)\n  errorMessage      String?                @db.Text\n  createdAt         DateTime               @default(now())\n  updatedAt         DateTime               @updatedAt\n\n  @@unique([scriptId, orderIndex])\n  @@index([scriptId, orderIndex])\n  @@index([status, createdAt(sort: Desc)])\n}\n\n// ─── Extracted Element (reusable subject/material cutout) ────────\n//\n// Stores the result of /studio/edit/extract-element runs so the user can drop\n// them into future generations as reference material. The cutout PNG lives in\n// R2 (extractedStorageKey); the optional sourceGenerationId links back to the\n// internal source image when the extract came from an existing Generation,\n// otherwise sourceImageUrl alone holds the input reference.\n\nmodel ExtractedElement {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  sourceGenerationId String?\n  sourceGeneration   Generation? @relation(\"ExtractedElementSource\", fields: [sourceGenerationId], references: [id], onDelete: SetNull)\n  sourceImageUrl     String      @db.Text\n\n  extractedUrl        String  @db.Text\n  extractedStorageKey String\n  thumbnailUrl        String? @db.Text\n  thumbnailStorageKey String?\n\n  width  Int @default(1024)\n  height Int @default(1024)\n\n  name   String\n  prompt String  @db.Text\n  invert Boolean @default(false)\n\n  provider String // \"fal\" | \"gemini\" | \"openai\"\n  modelId  String\n\n  createdAt DateTime @default(now())\n\n  @@index([userId, createdAt(sort: Desc)])\n  @@index([sourceGenerationId])\n}\n",
